package cliutil

import (
	"fmt"
	"math"
	"net/http"
	"strconv"
	"strings"
	"sync"
	"time"
)

// AdaptiveLimiter paces outbound requests with adaptive ceiling discovery.
// Starts at a floor rate, ramps up after consecutive successes, halves on 429
// and records a ceiling. Per-session only — not persisted. Methods are safe
// to call on a nil receiver.
// PATCH: AdaptiveLimiter gains a `disabled` field (set by SetRate(0)).
type AdaptiveLimiter struct {
	mu          sync.Mutex
	rate        float64
	floor       float64
	ceiling     float64
	successes   int
	rampAfter   int
	lastRequest time.Time // zero-value: first Wait() returns immediately
	// disabled is set by SetRate(0). When true, Wait() returns immediately
	// without sleeping. This lets a user pass --rate-limit 0 to disable
	// rate-limiting without requiring callers to swap defaultClient.limiter
	// to nil (which would race with in-flight do() calls).
	disabled bool
}

// NewAdaptiveLimiter returns a limiter starting at ratePerSec, or nil when
// rate-limiting should be disabled. Methods on the nil limiter no-op.
func NewAdaptiveLimiter(ratePerSec float64) *AdaptiveLimiter {
	if ratePerSec <= 0 {
		return nil
	}
	return &AdaptiveLimiter{
		rate:      ratePerSec,
		floor:     ratePerSec,
		rampAfter: 10,
	}
}

func (l *AdaptiveLimiter) Wait() {
	if l == nil {
		return
	}
	l.mu.Lock()
	if l.disabled {
		l.mu.Unlock()
		return
	}
	delay := time.Duration(float64(time.Second) / l.rate)
	elapsed := time.Since(l.lastRequest)
	l.mu.Unlock()
	if elapsed < delay {
		time.Sleep(delay - elapsed)
	}
	l.mu.Lock()
	l.lastRequest = time.Now()
	l.mu.Unlock()
}

// PATCH: SetRate method for in-place rate change without pointer swap.
//
// SetRate adjusts the limiter's per-second cap in place under the existing
// mutex. Passing rps <= 0 disables rate limiting (Wait returns immediately).
// Any positive value sets it as the new floor and current rate, and clears
// the discovered ceiling so the adaptive ramp can re-discover. Safe to call
// concurrently with Wait/OnSuccess/OnRateLimit on the same limiter; the
// existing OnRateLimit/OnSuccess history is preserved across rate changes
// (no pointer swap means no history loss). Methods on a nil receiver no-op.
func (l *AdaptiveLimiter) SetRate(rps float64) {
	if l == nil {
		return
	}
	l.mu.Lock()
	defer l.mu.Unlock()
	if rps <= 0 {
		l.disabled = true
		return
	}
	l.disabled = false
	l.rate = rps
	l.floor = rps
	l.ceiling = 0
	l.successes = 0
}

func (l *AdaptiveLimiter) OnSuccess() {
	if l == nil {
		return
	}
	l.mu.Lock()
	defer l.mu.Unlock()
	l.successes++
	if l.successes >= l.rampAfter {
		newRate := l.rate * 1.25
		if l.ceiling > 0 && newRate > l.ceiling*0.9 {
			newRate = l.ceiling * 0.9
		}
		l.rate = newRate
		l.successes = 0
	}
}

func (l *AdaptiveLimiter) OnRateLimit() {
	if l == nil {
		return
	}
	l.mu.Lock()
	defer l.mu.Unlock()
	l.ceiling = l.rate
	l.rate = l.rate / 2
	if l.rate < 0.5 {
		l.rate = 0.5
	}
	l.successes = 0
}

func (l *AdaptiveLimiter) Rate() float64 {
	if l == nil {
		return 0
	}
	l.mu.Lock()
	defer l.mu.Unlock()
	return l.rate
}

// RateLimitError signals an upstream returned 429 after retries were
// exhausted. Callers must surface this as a hard error rather than empty
// results — empty-on-throttle is indistinguishable from "no data exists"
// and silently corrupts downstream queries.
type RateLimitError struct {
	URL        string
	RetryAfter time.Duration
	Body       string
}

func (e *RateLimitError) Error() string {
	msg := fmt.Sprintf("rate limited: HTTP 429 for %s", e.URL)
	if e.RetryAfter > 0 {
		msg += fmt.Sprintf("; retry after %s", e.RetryAfter)
	}
	if body := strings.TrimSpace(e.Body); body != "" {
		msg += ": " + body
	}
	return msg
}

// PATCH: BotChallengeError sentinel for datadome / Akamai responses.
//
// BotChallengeError signals an upstream returned a bot-defense challenge
// (datadome, Akamai/Kona, or similar) that cannot be retried automatically.
// Callers should surface the Remediation hint to the user rather than
// retry blindly — sustained automated retries against a challenge response
// can escalate to an IP or account block.
type BotChallengeError struct {
	URL             string
	ChallengeType   string // "datadome", "akamai", or "unknown-403"
	StatusCode      int
	Remediation     string
	ResponseSnippet string // first ~200 chars of body, for debugging only
}

func (e *BotChallengeError) Error() string {
	msg := fmt.Sprintf("bot challenge: HTTP %d for %s", e.StatusCode, e.URL)
	if e.ChallengeType != "" {
		msg += " (" + e.ChallengeType + ")"
	}
	if e.Remediation != "" {
		msg += "; " + e.Remediation
	}
	return msg
}

// MaxRetryWait caps the wait derived from a Retry-After header so a buggy
// or hostile upstream cannot pin a CLI for hours.
const MaxRetryWait = 60 * time.Second

// RetryAfter parses an HTTP Retry-After header (RFC 7231: delta-seconds or
// HTTP-date), capped at MaxRetryWait. Returns 5s when missing or unparseable.
func RetryAfter(resp *http.Response) time.Duration {
	if resp == nil {
		return 5 * time.Second
	}
	header := strings.TrimSpace(resp.Header.Get("Retry-After"))
	if header == "" {
		return 5 * time.Second
	}
	if seconds, err := strconv.Atoi(header); err == nil {
		d := time.Duration(seconds) * time.Second
		if d > MaxRetryWait {
			return MaxRetryWait
		}
		if d <= 0 {
			return 5 * time.Second
		}
		return d
	}
	if t, err := http.ParseTime(header); err == nil {
		wait := time.Until(t)
		if wait > MaxRetryWait {
			return MaxRetryWait
		}
		if wait > 0 {
			return wait
		}
	}
	return 5 * time.Second
}

// MaxBackoff caps Backoff so tests stay bounded. Callers needing jitter
// add their own; the bare exponential keeps the contract deterministic.
const MaxBackoff = 30 * time.Second

// Backoff returns 2^attempt seconds capped at MaxBackoff.
func Backoff(attempt int) time.Duration {
	if attempt < 0 {
		attempt = 0
	}
	wait := time.Duration(math.Pow(2, float64(attempt))) * time.Second
	if wait > MaxBackoff {
		return MaxBackoff
	}
	return wait
}
